Peter, 12
Lucy, 78&#34;; if(csv.parse(content)){ const auto header = csv.header(); for (const auto row: csv) { for (const auto cell: row) { // Do something with cell value std::string value; cell.read_value(value); cout &lt;&lt; value &lt;&lt; &#34; &#34;; } cout &lt;&lt; &#34;
&#34;; } } } 从字符串中解析内容: #include &#34;csv2/reader.hpp&#34; #include &lt;string&gt; using namespace std; int main(){ csv2::Reader&lt;csv2::delimiter&lt;&#39;,&#39;&gt;, csv2::quote_character&lt;&#39;&#34;&#39;&gt;, csv2::first_row_is_header&lt;true&gt;, csv2::trim_policy::trim_whitespace&gt; csv; if(csv.mmap(&#34;demo.csv&#34;)){ const auto header = csv.header(); for (const auto row: csv) { for (const auto cell: row) { // Do something with cell value std::string value; cell.read_value(value); cout &lt;&lt; value &lt;&lt; &#34; &#34;; } cout &lt;&lt; &#34;
&#34;; } } } parse方法中使用了知识点 10。 reader.hpp 中还定义了Cell、Row、RowIterator等类。 为了方便在之后的类中使用 RowIterator、Row 和 CellIterator，文件中加了 forward-declaration，如上图所示。 CellCell 类的数据部分定义如下: 其中的buffer_指向 memory-mapped buffer，可参考知识点 4，我们可以简单的将其理解为指向数据内容的一个指针。 主要包括两个方法: read_raw_value和read_value，两个方法稍有区别，前者处理无转义字符，后者处理有转义字符。 RowRow 类的数据部分定义如下: 和 Cell 类的定义大同小异。Row 类中还定义了另一个类 CellIterator: class CellIterator { friend class Row; const char *buffer_; size_t buffer_size_; size_t start_; size_t current_; size_t end_; public: CellIterator(const char *buffer, size_t buffer_size, size_t start, size_t end) : buffer_(buffer), buffer_size_(buffer_size), start_(start), current_(start_), end_(end) { } CellIterator &amp;operator++() { current_ += 1; return *this; } Cell operator*() { bool escaped{false}; class Cell cell; cell.buffer_ = buffer_; cell.start_ = current_; cell.end_ = end_; size_t last_quote_location = 0; bool quote_opened = false; for (auto i = current_; i &lt; end_; i++) { current_ = i; if (buffer_[i] == delimiter::value &amp;&amp; !quote_opened) { // actual delimiter // end of cell cell.end_ = current_; cell.escaped_ = escaped; return cell; } else { if (buffer_[i] == quote_character::value) { if (!quote_opened) { // first quote for this cell quote_opened = true; last_quote_location = i; } else { escaped = (last_quote_location == i - 1); last_quote_location += (i - last_quote_location) * size_t(!escaped); quote_opened = escaped || (buffer_[i + 1] != delimiter::value); } } } } cell.end_ = current_ + 1; return cell; } bool operator!=(const CellIterator &amp;rhs) { return current_ != rhs.current_; } }; CellIterator 中定义了自增操作符、取值操作符和不等操作符。Iterator 必须实现这三个操作符: #include &lt;iostream&gt; using namespace std; // forward-declaration to allow use in Iter class IntVector; class Iter { public: Iter (const IntVector* p_vec, int pos) : _pos( pos ) , _p_vec( p_vec ) { } // these three methods form the basis of an iterator for use with // a range-based for loop bool operator!= (const Iter&amp; other) const { return _pos != other._pos; } // this method must be defined after the definition of IntVector // since it needs to use it int operator* () const; const Iter&amp; operator++ () { ++_pos; // although not strictly necessary for a range-based for loop // following the normal convention of returning a value from // operator++ is a good idea. return *this; } private: int _pos; const IntVector *_p_vec; }; class IntVector { public: IntVector () { } int get (int col) const { return _data[ col ]; } Iter begin () const { return Iter( this, 0 ); } Iter end () const { return Iter( this, 100 ); } void set (int index, int val) { _data[ index ] = val; } private: int _data[ 100 ]; }; int Iter::operator* () const { return _p_vec-&gt;get( _pos ); }

