&#34;, argv[0]); exit(1); } if (WSAStartup(MAKEWORD(2, 2), &amp;wsaData) != 0) ErrorHandling(&#34;WSAStartup() error!&#34;); hServerSocket = socket(PF_INET, SOCK_STREAM, 0); if (hServerSocket == INVALID_SOCKET) ErrorHandling(&#34;socket() error!&#34;); memset(&amp;serverAddr, 0, sizeof(serverAddr)); serverAddr.sin_family = AF_INET; serverAddr.sin_addr.s_addr = htonl(INADDR_ANY); serverAddr.sin_port = htons(atoi(argv[1])); if (bind(hServerSocket, (sockaddr*)&amp;serverAddr, sizeof(serverAddr)) == SOCKET_ERROR) { ErrorHandling(&#34;bind() error!&#34;); } if (listen(hServerSocket, 5) == SOCKET_ERROR) { ErrorHandling(&#34;listen() error!&#34;); } clientAddrSize = sizeof(clientAddr); for (i = 0; i &lt; 5; i++) { hClientSocket = accept(hServerSocket, (sockaddr*)&amp;clientAddr, &amp;clientAddrSize); if (hClientSocket == -1) ErrorHandling(&#34;accept() error!&#34;); else std::cout &lt;&lt; &#34;Connected client &#34; &lt;&lt; i + 1 &lt;&lt; &#34;
&#34;; while ((strlen = recv(hClientSocket, message, BUF_SIZE, 0)) != 0) { send(hClientSocket, message, strlen, 0); } closesocket(hClientSocket); } closesocket(hServerSocket); WSACleanup(); return 0; } void ErrorHandling(const char* message) { fputs(message, stderr); fputc(&#39;
