&#34;, argv[0]); exit(1); } if (WSAStartup(MAKEWORD(2, 2), &amp;wsaData) != 0) ErrorHandling(&#34;WSAStartup() error!&#34;); hSocket = socket(PF_INET, SOCK_STREAM, 0); if (hSocket == INVALID_SOCKET) ErrorHandling(&#34;socket() error&#34;); memset(&amp;serverAddr, 0, sizeof(serverAddr)); serverAddr.sin_family = AF_INET; serverAddr.sin_addr.s_addr = inet_addr(argv[1]); serverAddr.sin_port = htons(atoi(argv[2])); if (connect(hSocket, (sockaddr*)&amp;serverAddr, sizeof(serverAddr)) == SOCKET_ERROR) { ErrorHandling(&#34;connect() error!&#34;); } while (1) { fputs(&#34;Input message (Q to quit): &#34;, stdout); fgets(message, BUF_SIZE, stdin); if (!strcmp(message, &#34;q
&#34;) || !strcmp(message, &#34;Q
&#34;)) break; send(hSocket, message, strlen(message), 0); strLen = recv(hSocket, message, BUF_SIZE - 1, 0); message[strLen] = 0; printf(&#34;Message from server : %s&#34;, message); } closesocket(hSocket); WSACleanup(); return 0; } void ErrorHandling(const char* message) { fputs(message, stderr); fputc(&#39;
