&#34;, argv[0]); exit(1); } sock = socket(PF_INET, SOCK_STREAM, 0); if (sock == -1) { error_handling(&#34;socket() error&#34;); } memset(&amp;serv_addr, 0, sizeof(serv_addr)); serv_addr.sin_family = AF_INET; serv_addr.sin_addr.s_addr = inet_addr(argv[1]); serv_addr.sin_port = htons(atoi(argv[2])); if (connect(sock, (struct sockaddr *)&amp;serv_addr, sizeof(serv_addr)) == -1) { error_handling(&#34;connect() error&#34;); } else { puts(&#34;connected....&#34;); } while (1) { fputs(&#34;Input message (Q to quit): &#34;, stdout); fgets(message, BUF_SIZE, stdin); if (!strcmp(message, &#34;q
