&#34;)) { break; } str_len = write(sock, message, strlen(message)); recv_len = 0; while (recv_len &lt; str_len) { recv_cnt = read(sock, &amp;message[recv_len], BUF_SIZE - 1); if (recv_cnt == -1) { error_handling(&#34;read() error&#34;); } recv_len += recv_cnt; } message[recv_len] = 0; printf(&#34;Message from server : %s&#34;, message); } close(sock); return 0; } void error_handling(char *message) { fputs(message, stderr); fputc(&#39;
