&#34;, argv[0]); exit(1); } if (WSAStartup(MAKEWORD(2, 2), &amp;wsData) != 0) ErrorHandling(&#34;WSAStartup() error!&#34;); serverSocket = socket(PF_INET, SOCK_STREAM, 0); if (serverSocket == INVALID_SOCKET) ErrorHandling(&#34;socket() error!&#34;); memset(&amp;serverAddr, 0, sizeof(serverAddr)); serverAddr.sin_family = PF_INET; serverAddr.sin_port = htons(atoi(argv[1])); serverAddr.sin_addr.s_addr = htonl(INADDR_ANY); if (bind(serverSocket, (SOCKADDR*)&amp;serverAddr, sizeof(serverAddr)) == SOCKET_ERROR) ErrorHandling(&#34;bind() error!&#34;); if (listen(serverSocket, 5) == SOCKET_ERROR) ErrorHandling(&#34;listen() error!&#34;); clientAddrSize = sizeof(clientAddr); for (i = 0; i &lt; 5; i++) { opndCount = 0; clientSocket = accept(serverSocket, (SOCKADDR*)&amp;clientAddr, &amp;clientAddrSize); recv(clientSocket, (char*)&amp;opndCount, 1, 0); recvLen = 0; while ((opndCount * OPZS + 1) &gt; recvLen) { recvCount = recv(clientSocket, opinfo, BUF_SIZE - 1, 0); recvLen += recvCount; } result = calculate(opndCount, (int*)opinfo, opinfo[recvLen - 1]); send(clientSocket, (char*)&amp;result, sizeof(result), 0); closesocket(clientSocket); } closesocket(serverSocket); WSACleanup(); return 0; } void ErrorHandling(const char* message) { fputs(message, stderr); fputc(&#39;
&#39;, stderr); exit(1); } int calculate(int opnum, int opnds[], char op) { int result = opnds[0], i; switch (op) { case &#39;+&#39;: for (i = 1; i &lt; opnum; i++) result += opnds[i]; break; case &#39;-&#39;: for (i = 1; i &lt; opnum; i++) result -= opnds[i]; break; case &#39;*&#39;: for (i = 1; i &lt; opnum; i++) result *= opnds[i]; break; } return result; } 客户端op_client.c #include &lt;iostream&gt; #include &lt;WinSock2.h&gt; #include &lt;cstdlib&gt; #include &lt;cstdio&gt; ##pragma warning(disable:4996) ##define BUF_SIZE 1024 ##define RLT_SIZE 4 ##define OPSZ 4 void ErrorHandling(const char* message); int main(int argc, char* argv[]) { WSADATA wsData; SOCKET hSocket; char opmsg[BUF_SIZE]; int result, opndCount, i; SOCKADDR_IN serverAddr; if (argc != 3) { printf(&#34;Usage : %s &lt;IP&gt; &lt;port&gt;
&#34;, argv[0]); exit(1); } if (WSAStartup(MAKEWORD(2, 2), &amp;wsData) != 0) { ErrorHandling(&#34;WSAStartup() error!&#34;); } hSocket = socket(PF_INET, SOCK_STREAM, 0); if (hSocket == INVALID_SOCKET) ErrorHandling(&#34;socket() error!&#34;); memset(&amp;serverAddr, 0, sizeof(serverAddr)); serverAddr.sin_addr.s_addr = inet_addr(argv[1]); serverAddr.sin_family = AF_INET; serverAddr.sin_port = htons(atoi(argv[2])); if (connect(hSocket, (SOCKADDR*)&amp;serverAddr, sizeof(serverAddr)) == SOCKET_ERROR) ErrorHandling(&#34;socket() error!&#34;); else puts(&#34;Connected ......&#34;); fputs(&#34;Operand count : &#34;, stdout); scanf(&#34;%d&#34;, &amp;opndCount); opmsg[0] = (char)opndCount; for (i = 0; i &lt; opndCount; i++) { printf(&#34;Operand %d : &#34;, i + 1); scanf(&#34;%d&#34;, (int*)&amp;opmsg[i * OPSZ + 1]); } fgetc(stdin); fputs(&#34;Operator : &#34;, stdout); scanf(&#34;%c&#34;, &amp;opmsg[opndCount * OPSZ + 1]); send(hSocket, opmsg, opndCount * OPSZ + 2, 0); recv(hSocket, (char*)&amp;result, RLT_SIZE, 0); printf(&#34;Operation result : %d 
&#34;, result); closesocket(hSocket); WSACleanup(); return 0; } void ErrorHandling(const char* message) { fputs(message, stderr); fputc(&#39;
